import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { 
  faEnvelope, 
  faEye, 
  faEyeSlash, 
  faArrowRight,
  faUser,
  faWrench,
  faStar
} from '@fortawesome/free-solid-svg-icons';
import { faGoogle, faFacebook, faTwitter, faInstagram, faLinkedin } from '@fortawesome/free-brands-svg-icons';
import './Auth.css';

const Login = () => {
  const [userType, setUserType] = useState('user'); // 'user' or 'tasker'
  const [showPassword, setShowPassword] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });

  const handleInputChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Handle login logic here
    console.log('Login data:', { ...formData, userType, rememberMe });
  };

  return (
    <div className={`auth-container ${userType === 'tasker' ? 'yellow-theme' : ''}`}>
      <div className="auth-background">
        {/* Background decorative shapes */}
        <div className="bg-shape bg-circle-1"></div>
        <div className="bg-shape bg-circle-2"></div>
        <div className="bg-shape bg-diamond-1"></div>
        <div className="bg-shape bg-diamond-2"></div>
      </div>

      <div className="auth-content">
        {/* Logo */}
        <div className="auth-logo">
          <div className="logo-icon">
            <div className="house-icon">
              <div className="house-roof"></div>
              <div className="house-body">
                <span>H</span>
              </div>
            </div>
          </div>
          <h1 className="logo-text">HomeHelper</h1>
        </div>

        {/* User Type Selector */}
        <div className="user-type-selector">
          <button 
            className={`type-option ${userType === 'user' ? 'active' : ''}`}
            onClick={() => setUserType('user')}
          >
            <FontAwesomeIcon icon={faUser} />
            <span>User</span>
          </button>
          <button 
            className={`type-option ${userType === 'tasker' ? 'active' : ''}`}
            onClick={() => setUserType('tasker')}
          >
            <FontAwesomeIcon icon={faWrench} />
            <span>Tasker</span>
          </button>
        </div>

        {/* Login Form */}
        <div className="auth-card">
          <h2 className="auth-title">Sign In</h2>
          <p className="auth-subtitle">
            {userType === 'user' ? 'Welcome back!' : 'Welcome back, helper!'}
          </p>

          <form onSubmit={handleSubmit} className="auth-form">
            <div className="form-group">
              <input
                type="text"
                name="email"
                placeholder="Email or phone number"
                value={formData.email}
                onChange={handleInputChange}
                required
              />
              <FontAwesomeIcon icon={faEnvelope} className="input-icon" />
            </div>

            <div className="form-group">
              <input
                type={showPassword ? 'text' : 'password'}
                name="password"
                placeholder="Password"
                value={formData.password}
                onChange={handleInputChange}
                required
              />
              <FontAwesomeIcon 
                icon={showPassword ? faEyeSlash : faEye} 
                className="input-icon clickable"
                onClick={() => setShowPassword(!showPassword)}
              />
            </div>

            <div className="form-options">
              <label className="checkbox-label">
                <input
                  type="checkbox"
                  checked={rememberMe}
                  onChange={(e) => setRememberMe(e.target.checked)}
                />
                <span>Remember me</span>
              </label>
              <Link to="/forgot-password" className="forgot-password">
                Forgot password?
              </Link>
            </div>

            <button type="submit" className="auth-button primary">
              <span>Sign In</span>
              <FontAwesomeIcon icon={faArrowRight} />
            </button>
          </form>

          {/* Social Login */}
          <div className="social-separator">
            <span>Or continue with</span>
          </div>

          <div className="social-buttons">
            <button className="social-button google">
              <FontAwesomeIcon icon={faGoogle} />
              <span>Continue with Google</span>
            </button>
            <button className="social-button facebook">
              <FontAwesomeIcon icon={faFacebook} />
              <span>Continue with Facebook</span>
            </button>
          </div>

          {/* Register Link */}
          <div className="auth-link">
            <span>Don't have an account? </span>
            <Link to="/register" className="link-text">Sign up now</Link>
          </div>
        </div>

        {/* Footer */}
        <div className="auth-footer">
          <p className="terms-text">
            By continuing, you agree to our{' '}
            <a href="#" className="link-text">Terms of Service</a> and{' '}
            <a href="#" className="link-text">Privacy Policy</a>
          </p>
          
          <div className="social-icons">
            <a href="#" className="social-icon">
              <FontAwesomeIcon icon={faFacebook} />
            </a>
            <a href="#" className="social-icon">
              <FontAwesomeIcon icon={faTwitter} />
            </a>
            <a href="#" className="social-icon">
              <FontAwesomeIcon icon={faInstagram} />
            </a>
            <a href="#" className="social-icon">
              <FontAwesomeIcon icon={faLinkedin} />
            </a>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
